10,0.01893601,0.00833550,0.11342190,0.02658940,-0.02597567,0.00499323,0.04963344,0.03313754,-0.01942122,0.06887314,-0.04528258,-0.01914204,-0.09415861,0.03581641,-0.05762809,0.00269783,0.04193236,-0.04715278,-0.00736789,0.00190806,0.01192382,0.06254806,0.01380218,-0.07545470,-0.05342621,-0.03498271,-0.00937132,-0.05250274,-0.10528582,-0.05708093,-0.01101430,0.00160425,0.07764448,-0.03685944,-0.06265110,-0.04931145,0.02124611,-0.01784237,0.01090837,0.03504125,0.04449970,0.03267370]',E'HTTP Service Groups\n\n@Bean\n		public RestClientHttpServiceGroupConfigurer groupConfigurer() {\n			return groups -> {\n				// configure client for group "echo"\n				groups.filterByName("echo").forEachClient((group, clientBuilder) -> ...);\n\n				// configure the clients for all groups\n				groups.forEachClient((group, clientBuilder) -> ...);\n\n				// configure client and proxy factory for each group\n				groups.forEachGroup((group, clientBuilder, factoryBuilder) -> ...);\n			};\n		}\n	}\n----','{"source": "spring-framework", "version": "7", "language": "java", "title": "Rest Clients.Adoc", "section_title": "rest-clients.adoc", "url": "https://github.com/spring-projects/spring-framework/blob/main/framework-docs/modules/ROOT/pages/integration/rest-clients.adoc", "topics": "spring,framework,rest,clients.adoc", "categories": "java,enterprise,ioc,web"}');
